ruleContent:
// 兼容 Rhino 的脚本（ES5）
var urls = [];
var resultStr = String(result || '');   // 确保 result 存在

// 从 HTML 中提取 m3u8 链接
function getM3u8(html) {
    html = html || resultStr;
    var urlRegex = /(https?:[^'"\s]*?\.m3u8[^'"\s]*)/g;
    var urlSet = [];
    var match;
    while ((match = urlRegex.exec(html)) !== null) {
        var ul = match[1].replace(/\\/g, "");
        if (urlSet.indexOf(ul) === -1) {
            urlSet.push(ul);
        }
    }
    return urlSet;
}

// 更新进度条（可选）
function updateProgress(current, total) {
    var percentage = Math.round(current / total * 10000) / 100;
    var blocks = Math.floor(percentage / 10);
    var progressBar = "";
    for (var i = 0; i < blocks; i++) progressBar += "█";
    for (var i = blocks; i < 10; i++) progressBar += "░";
    java.longToast("【加载进度】\n" + progressBar + " \n" + percentage + "%");
}

// 判断是否需要点开详情页
if (/点我/.test(resultStr) && /查看详情/.test(resultStr)) {
    // 获取所有详情页链接
    var list = java.getElements('@@#post>article>.post-content>p>a');
    var links = [];
    for (var i = 0; i < list.length - 1; i++) {  // 去掉最后一个
        links.push(list[i]);
    }
    var tempUrls = [];
    for (var idx = 0; idx < links.length; idx++) {
        updateProgress(idx + 1, links.length);
        var link = links[idx];
        var href = String(link.getAttribute('href'));
        var fullUrl = source.key + href;   // 需要确保 source.key 存在
        var doc = String(java.ajax(fullUrl));
        var pageUrls = getM3u8(doc);
        tempUrls = tempUrls.concat(pageUrls);
        if (idx === links.length - 1) {
            urls = tempUrls;
        }
    }
} else {
    urls = getM3u8();
}

// 如果没有获取到任何视频地址，显示错误信息
if (!urls || urls.length === 0) {
    '<html><body><h2>未找到视频地址，请检查规则或网站结构</h2></body></html>';
} else {
    // 生成 HTML 页面（注意转义）
    var htmlOutput = '<html>' +
        '<head>' +
        '<meta name="viewport" content="width=device-width">' +
        '<style>' +
        'body{margin:0;font-family:Arial,sans-serif;background:linear-gradient(135deg,#ece9e6,#fff);display:flex;flex-direction:column;align-items:center;justify-content:flex-start;padding:20px;}' +
        '.container{width:100%;max-width:800px;background:#fff;border-radius:10px;box-shadow:0 4px 8px rgba(0,0,0,0.1);overflow:hidden;margin-bottom:20px;}' +
        'h3{text-align:center;margin:0;padding:10px 20px;font-size:0.9em;background:#333;color:#fff;border-radius:10px 10px 0 0;}' +
        '.video-container{width:100%;background:#000;position:relative;}' +
        'video{width:100%;height:auto;display:block;}' +
        '.nav-container{display:flex;justify-content:space-between;align-items:center;padding:15px 20px;background:#f5f5f5;border-top:1px solid #ddd;}' +
        '.nav-button{padding:10px 20px;background:#007bff;color:white;border:none;border-radius:5px;cursor:pointer;font-size:14px;}' +
        '.nav-button:disabled{background:#6c757d;cursor:not-allowed;}' +
        '.page-select{padding:10px 15px;border:1px solid #ddd;border-radius:5px;font-size:14px;background:white;min-width:120px;}' +
        '</style>' +
        '</head>' +
        '<body>' +
        '<div class="container">' +
        '<h3>当前播放: 第<span id="currentVideo">1</span>集 / 共' + urls.length + '集</h3>' +
        '<div class="video-container">' +
        '<video controls autoplay name="media" id="videoPlayer">' +
        '<source src="' + urls[0] + '" type="application/x-mpegURL">' +
        '</video>' +
        '</div>' +
        '<div class="nav-container">' +
        '<button class="nav-button" id="prevBtn" onclick="changeVideo(-1)">上一集</button>' +
        '<select class="page-select" id="pageSelect"></select>' +
        '<button class="nav-button" id="nextBtn" onclick="changeVideo(1)">下一集</button>' +
        '</div>' +
        '</div>' +
        '<script>' +
        'var videoUrls = ' + JSON.stringify(urls) + ';' +
        'var currentVideoIndex = 0;' +
        'var video = document.getElementById("videoPlayer");' +
        'var prevBtn = document.getElementById("prevBtn");' +
        'var nextBtn = document.getElementById("nextBtn");' +
        'var pageSelect = document.getElementById("pageSelect");' +
        'var currentVideoSpan = document.getElementById("currentVideo");' +
        'function generateSelectOptions() {' +
        '    var optionsHtml = "";' +
        '    for (var i = 0; i < videoUrls.length; i++) {' +
        '        optionsHtml += "<option value=\\"" + i + "\\">第" + (i+1) + "集</option>";' +
        '    }' +
        '    pageSelect.innerHTML = optionsHtml;' +
        '}' +
        'function updateButtons() {' +
        '    prevBtn.disabled = (currentVideoIndex === 0);' +
        '    nextBtn.disabled = (currentVideoIndex === videoUrls.length - 1);' +
        '    pageSelect.value = currentVideoIndex;' +
        '    currentVideoSpan.textContent = currentVideoIndex + 1;' +
        '}' +
        'function changeVideo(direction) {' +
        '    var newIndex = currentVideoIndex + direction;' +
        '    if (newIndex >= 0 && newIndex < videoUrls.length) {' +
        '        currentVideoIndex = newIndex;' +
        '        video.src = videoUrls[currentVideoIndex];' +
        '        video.load();' +
        '        updateButtons();' +
        '    }' +
        '}' +
        'function selectVideo(index) {' +
        '    var newIndex = parseInt(index, 10);' +
        '    if (newIndex >= 0 && newIndex < videoUrls.length) {' +
        '        currentVideoIndex = newIndex;' +
        '        video.src = videoUrls[currentVideoIndex];' +
        '        video.load();' +
        '        updateButtons();' +
        '    }' +
        '}' +
        'pageSelect.onchange = function() { selectVideo(this.value); };' +
        'generateSelectOptions();' +
        'updateButtons();' +
        '</script>' +
        '</body>' +
        '</html>';

    htmlOutput;
}

